案例代码：
entity dff is
port (
	  clk, data: in std_logic;
	  q: out std_logic
	  );
end entity;
architecture basic of dff is
begin
process ( clk ) is
begin
 if ( clk'event and clk = '1' ) then
  q <= data;  //实例“top.u_dff_2”的触发器“q”的时钟输入无法直接被外部输入的控制，扫描插入工具会将其排除在外。
 end if;
end process;
end architecture;
entity top is
port (
	  clk, gate, data1, data2: in std_logic;
	  out1: out std_logic;
	  out2: out std_logic
	  );
end entity;
architecture basic of top is
signal clk_gate: std_logic;
begin
 clk_gate <= clk or gate;
   u_dff_1 : entity dff port map ( clk => clk, data => data1, q => out1 );
   u_dff_2 : entity dff port map ( clk =>clk_gate, data => data2, q => out2 );
end architecture;

案例代码：
library IEEE;
use IEEE.std_logic_1164.all;
entity ENCODER is
  port (
		A : in std_logic_vector(7 downto 0);
		Y : out std_logic_vector(2 downto 0));
end ENCODER;
architecture RTL of ENCODER is
begin
 process (A) begin
  case A is
	when "01111111" => Y <= "000";
	when "10111111" => Y <= "001";
	when "11011111" => Y <= "010";
	when "11101111" => Y <= "011";
	when "11110111" => Y <= "100";
	when "11111011" => Y <= "101";
	when "11111101" => Y <= "110";
	when "11111110" => Y <= "111";
	when others => Y <= "XXX";    //使用‘X’赋值可减小电路面积，但会生成包含未知值的电路，应避免这种给航天器产品造成危险的行为。
   end case;
 end process;

案例代码：
entity ee is
port(
	 clock: in std_logic;
	 reset: in std_logic;		//信号“reset”被同时用于同步和异步信号线，为避免逻辑综合和布局的问题，不要将同一个信号线同时用于同步和异步功能
	 d1, d2: in std_logic;
	 q1, q2: out std_logic
);
end entity ee;

architecture RTL of ee is
begin
process (clock) begin
if clock'event and clock='0' then
if reset='1' then		//连接到同步复位端
	 q1 <= '0';
else
	 q1 <= d1;
end if;
end if;
end process;

process (clock, reset) begin
if reset='1' then		//连接到异步复位端
	 q2 <= '0';
elsif clock'event and clock='0' then
	 q2 <= d2;
end if;
end process;
end architecture;

