process (clk, reset, set) begin //触发器q引用了两个异步置位和异步复位控制。推荐使用单独的异步复位控制。
if ( reset = '1' ) then   //异步复位控制。
  q <= '0';
elsif ( set= '1' ) then   //异步置位控制。
  q <= '1';
elsif ( clk'event and clk = '1' ) then
  q <= data;
endif;
end process;

案例代码：  
entity ffg_c is
port (
	CLK, SEL, CTRL1, CTRL2, DATA : in std_logic;
	Q : out std_logic
	);
end entity;
architecture basic of ffg_c is
signal int_clk1, int_clk2, int_clk : std_logic;
begin
	int_clk1 <= CLK and CTRL1;
	int_clk2 <= CLK and CTRL2;
	int_clk <= int_clk2 when SEL = '1' else int_clk1;
process ( int_clk ) is
begin
if ( int_clk'event and int_clk = '1' ) then
	Q <= DATA;                                             //随机逻辑的输出作为了触发器“Q”的时钟
end if;
end process;
end architecture;

案例代码：
entity dff is
port (
	clk, reset, data: in std_logic;
	Q: out std_logic
	);
end;
architecture rtl of dff is
signal bf_rst: std_logic;
begin
	bf_rst <= '0' when reset = '1' else
		'1' when clk'event and clk = '1';
process ( clk, bf_rst ) begin                    //非全局复位信号被连接至触发器“Q”的异步复位端。为避免时序分析问题，只有初始复位能被用于异步复位
if bf_rst = '1' then                              //异步控制信号而不是全局复位信号
	Q <= '0';
elsif (clk'event and clk='1') then
	Q <= data;
end if;
end process;
end;

