variable F : std_logic;
begin
	F := '0';
for I in 0 to 3 loop                              //不应使用exit 和next 循环控制语句来控制循环，生成电路的规模可能明显增大
if( MODE = '1' and I < 2 ) then
	next;                                         //循环控制语句
end if;
F := F xor DIN(I);
end loop;
DOUT <= F;

