案例代码：
entity top is
port (
	  in1, in2, in3, clk1, clk2, reset, sel : in std_logic; //信号“clk1”被同时用作时钟和复位。不要混合使用时钟和复位以免DFT产生问题，此时扫描会排除所有时钟信号连接的部分。
	  out1, out2 : out std_logic
	  );
end entity;
architecture top_rtl of top is
signal mux_to_ff1, mux_to_ff2 : std_logic;
begin
 mux_to_ff2 <= clk1 when sel = '1' else
  in3;
 MUX_INSTANCE : entity mux port map ( in1 =>
clk1, in2 => in2 , sel => sel, out1 => mux_to_ff1
);
 DFF_INSTANCE1 : entity dff port map ( D => in1, CLK => mux_to_ff1, RESET => reset , Q => out1 ); //连接到“top. DFF_INSTANCE1”时钟端。
 DFF_INSTANCE2 : entity dff port map ( D => in1, CLK => clk2, RESET => mux_to_ff2, Q => out2 ); //连接到“top. DFF_INSTANCE2”异步复位端。
end architecture;

案例代码：
entity ff is
port(data0, data1: in std_logic_;
	 Q: out std_logic);
end entity ff;

architecture rtl of ff is
	 signal temp0, temp1: std_logic;
begin
	 temp0 <= data0 and temp1;
	 temp1 <= temp0 or data1;		//检测到类似RS锁存器的组合电路描述，避免使用基本单元生成锁存器，因为时序分析工具会把它看作是组合电路反馈
	 Q <= temp1;
end architecture rtl;

案例代码：
entity top is                                  
port( clk, din : in std_logic;
	dout1, dout2 : out std_logic);
end entity;
architecture RTL of top is
begin
process(clk)                                  
begin
if falling_edge(clk) then
	dout1 <= din;
end if;
end process;
process(clk)
begin
if rising_edge(clk) then            //同时使用了同一时钟的上升沿和下降沿
dout2 <= din;
end if;
end process;
end;

