案例代码：
entity dff is
port (
	clk_a, clk_b: in std_logic;
	data: std_logic;
	Q1, Q2: out std_logic
 );
end;
architecture rtl of top is
begin
process( clk_a )
begin
-- clk_a is auto-detected as the clock signal
if (clk_a'event and clk_a='1') then
	Q1 <= data;
end if;
end process;
process( clk_b )
begin
if (clk_b'event and clk_b='1') then
	Q2 <= clk_a;                             //将时钟信号连接至触发器的非时钟端将导致时序分析错误,全局时钟信号“clk_a”被连接至触发器“Q2”的数据输入端
end if;
end process;
end;

